Literal.Value:
'{
  "data": {"name": "dataset"},
  "facet": {
    "row": {
      "field": "Region",
      "sort": {
        "field": "KPI",
        "order": "descending"
      },
      "title": null,
      "header": {
        "labelFont": "Segoe UI",
        "labelColor": "black",
        "labelFontWeight": "bold",
        "labelFontSize": 12,
        "labelOrient": "top"
      }
    }
  },
  "spec": {
    "height": 80,
    "width": 530,
    "encoding": {
      "x": {
        "field": "Date",
        "type": "temporal",
        "title": null,
        "axis": {
          "tickCount": 8,
          "labelAlign": "left",
          "labelExpr": "[timeFormat(datum.value, ''%b''), timeFormat(datum.value, ''%m'') == ''01'' ? timeFormat(datum.value, ''%Y'') : '''']",
          "labelOffset": 4,
          "labelPadding": -24,
          "tickSize": 30,
          "gridDash": {
            "condition": {
              "test": {
                "field": "value",
                "timeUnit": "month",
                "equal": 1
              },
              "value": []
            },
            "value": [2, 2]
          },
          "tickDash": {
            "condition": {
              "test": {
                "field": "value",
                "timeUnit": "month",
                "equal": 1
              },
              "value": []
            },
            "value": [1,5]
          }
        }
      },
      "y": {
        "field": "KPI",
        "type": "quantitative",
        "title": null,
        "axis": {"format": ",.2s"}
      }
    },
    "layer": [
      {
        "mark": {
          "type": "line",
          "point": {
            "size": 15,
            "fill": "#FFB500"
          },
          "tooltip": true,
          "color": "#FFB500",
          "strokeWidth": 1.5
        },
        "encoding": {
          "x": {
            "field": "Date",
            "type": "temporal",
            "title": null
          },
          "y": {
            "field": "KPI",
            "type": "quantitative",
            "title": null,
            "axis": {"format": ",.2s"}
          },
          "tooltip": [
            {
              "field": "Region",
              "type": "nominal"
            },
            {
              "field": "Date",
              "type": "temporal"
            },
            {
              "field": "KPI",
              "type": "quantitative"
            }
          ]
        }
      },
      {
        "mark": "rule",
        "encoding": {
          "opacity": {
            "condition": {
              "value": 0.3,
              "param": "hover",
              "empty": false
            },
            "value": 0
          },
          "tooltip": [
            {
              "timeUnit": "yearmonthdate",
              "field": "Date",
              "title": "Date"
            },
            {
              "field": "Region",
              "type": "nominal"
            },
            {
              "field": "KPI",
              "type": "quantitative",
              "title": "Value",
              "format": ",.4s"
            }
          ]
        },
        "params": [
          {
            "name": "hover",
            "select": {
              "type": "point",
              "fields": [
                "Date",
                "Region"
              ],
              "nearest": true,
              "on": "mouseover",
              "clear": "mouseout"
            }
          }
        ]
      }
    ]
  },
  "resolve": {
    "scale": {"y": "independent"},
    "axis": {"x": "independent"}
  }
}'
